=Customer Details:
- Name: {{$json["name"]}}
- Email: {{$json["email"]}}
- Phone: {{$json["phone"]}}

Order Details:
- Product Name: {{$json["product_name"]}}
- Order Status: {{$json["order_status"]}}
- Payment Status: {{$json["payment_status"]}}

Generate a post-purchase message using the above data.

parameters.jsCode:
// Get all incoming items from Merge node
const items = $input.all();

// Item 0 = AI Agent output
// Item 1 = Database (Postgres) data
const aiItem = items.find(i => i.json.output);
const dataItem = items.find(i => i.json.name);

// Safely extract values
const aiText = (aiItem?.json.output || '').trim();
const cleanText = aiText.replace(/\n{3,}/g, '\n\n');

const customerName = dataItem?.json.name || '';
const productName = dataItem?.json.product_name || '';
const email = dataItem?.json.email || '';
const phone = dataItem?.json.phone || '';
const paymentStatus = dataItem?.json.payment_status || '';
const orderStatus = dataItem?.json.order_status || '';

// -------- EMAIL FORMAT --------
const emailMessage = `
Hi ${customerName},

${cleanText}

If you need any help, feel free to reply to this email and our support team will assist you.

Warm regards,  
Support Team
`.trim();

// -------- WHATSAPP FORMAT --------
const whatsappMessage = `
Hi ${customerName} 👋

${cleanText}

If you need help, just reply here 👍
`.trim();

// Return SINGLE clean item
return [
  {
    customer_name: customerName,
    product_name: productName,
    email: email,
    phone: phone,
    payment_status: paymentStatus,
    order_status: orderStatus,
    email_message: emailMessage,
    whatsapp_message: whatsappMessage
  }
];
